mapper.select:
SELECT rp.id, rp.user_id AS userId, COALESCE(u.nickname, '未知用户') AS nickname, u.avatar, rp.card_id AS cardId, DATE_FORMAT(rp.scheduled_date, '%Y-%m-%d') AS scheduledDate, c.front_content AS frontContent, c.back_content AS backContent, s.subject_name AS subjectName, c.difficulty_level AS difficultyLevel, rp.status FROM biz_review_plan rp INNER JOIN biz_card c ON rp.card_id = c.card_id AND c.del_flag = '0' LEFT JOIN biz_subject s ON c.subject_id = s.subject_id LEFT JOIN sys_user u ON rp.user_id = u.user_id
AND rp.user_id = #{userId}
AND rp.status = #{status}
AND rp.scheduled_date >= #{scheduledDateStart}
AND rp.scheduled_date <= #{scheduledDateEnd}
ORDER BY rp.scheduled_date DESC, rp.user_id ASC, rp.card_id ASC
